-- 付款单明细行 SELECT '' AS supplier, '付款单' AS documentType, f.name AS frame, DATE_FORMAT(o.time, '%Y-%m-%d') AS dateTime, o.number AS documentNumber, 0 AS accountsPayableIncrease, o.total AS advancePaymentIncrease, s.balance AS accountsPayableBalance, COALESCE(o.data, '') AS remark FROM supplier s INNER JOIN omy o ON s.id = o.supplier LEFT JOIN frame f ON o.frame = f.id
AND s.name LIKE CONCAT('%', #{query.supplier}, '%')
AND s.category = #{query.supplierType}
AND DATE(o.time) >= #{query.startTime}
AND DATE(o.time) <= #{query.endTime}
ORDER BY CASE WHEN supplier != '' THEN 1 ELSE 2 END, CASE WHEN documentType = '期初余额' THEN 1 WHEN documentType = '付款单' THEN 2 ELSE 3 END, dateTime DESC
